setPane("sv-clean-welcome-help", createSupportMacroContent("Welcome / How Can We Help", [{"label": "Use Case", "text": "Use when opening a conversation, replying to general feedback, or asking the customer how support can assist."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nThank you for using SUGO.\n\nYou are now speaking with SUGO Customer Service. How can we assist you today?\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "ترحيب وطلب توضيح الخدمة", [{"label": "الاستخدام", "text": "يستخدم عند بداية المحادثة أو عند الرد على ملاحظات عامة أو عند سؤال العميل عن طريقة المساعدة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nشكرًا لاستخدامك سوجو.\n\nأنت الآن تتواصل مع خدمة عملاء سوجو. كيف يمكننا مساعدتك اليوم؟\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-request-id", createSupportMacroContent("Request Customer ID", [{"label": "Use Case", "text": "Use when the customer reports an issue but did not provide the account ID."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo help you properly, please send us your SUGO ID.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب الآي دي", [{"label": "الاستخدام", "text": "يستخدم عندما يذكر العميل وجود مشكلة بدون إرسال الآي دي الخاص بالحساب."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nحتى نتمكن من مساعدتك بشكل صحيح، يرجى إرسال الآي دي الخاص بحسابك على سوجو.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-request-details-evidence", createSupportMacroContent("Request Details and Evidence", [{"label": "Use Case", "text": "Use when the issue is unclear and support needs the ID plus a screenshot or video."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nPlease send us your SUGO ID and a clear screenshot or screen recording showing the issue step by step, so we can review it accurately.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب تفاصيل ودليل المشكلة", [{"label": "الاستخدام", "text": "يستخدم عندما تكون المشكلة غير واضحة ويحتاج الدعم إلى الآي دي مع لقطة شاشة أو فيديو."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nيرجى إرسال الآي دي الخاص بحسابك على سوجو، مع لقطة شاشة واضحة أو فيديو تسجيل شاشة يوضح المشكلة خطوة بخطوة، حتى نتمكن من مراجعتها بدقة.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-same-account", createSupportMacroContent("Contact From the Same Account", [{"label": "Use Case", "text": "Use when the customer contacts support from an account different from the account that has the issue."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nFor security reasons, please contact us from the same account where the issue occurred, so we can verify the details and assist you properly.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "التواصل من نفس الحساب", [{"label": "الاستخدام", "text": "يستخدم عندما يتواصل العميل من حساب مختلف عن الحساب الذي توجد عليه المشكلة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nلأسباب تتعلق بأمان الحساب، يرجى التواصل معنا من نفس الحساب الذي ظهرت عليه المشكلة، حتى نتمكن من التحقق من التفاصيل ومساعدتك بشكل صحيح.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-request-submitted", createSupportMacroContent("Request Submitted / Follow Up", [{"label": "Use Case", "text": "Use after the agent has already submitted the customer request to the relevant team."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nYour request has been forwarded to the relevant department for review. Please follow up with us after 24 hours to check the latest update.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "تم رفع الطلب والمتابعة", [{"label": "الاستخدام", "text": "يستخدم بعد قيام الموظف برفع طلب العميل إلى القسم المختص."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nتم تحويل طلبك إلى القسم المختص للمراجعة. يرجى المتابعة معنا بعد 24 ساعة لمعرفة آخر تحديث.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-duplicate", createSupportMacroContent("Duplicate Conversation", [{"label": "Use Case", "text": "Use when the same inquiry has already been answered in another conversation."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nYour inquiry has already been answered in another conversation.\n\nPlease follow up through the same conversation to avoid duplication and help us serve you faster.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "محادثة مكررة", [{"label": "الاستخدام", "text": "يستخدم عندما يكون نفس الاستفسار قد تم الرد عليه في محادثة أخرى."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nتم الرد على استفسارك مسبقًا في محادثة أخرى.\n\nيرجى المتابعة من خلال نفس المحادثة لتجنب التكرار ولمساعدتك بشكل أسرع.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-ownership-questions", createSupportMacroContent("Account Ownership Questions", [{"label": "Use Case", "text": "Use for account binding, recovery, phone/email issues, or ownership verification."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo verify account ownership, please answer the following security questions in one message, in the same order:\n\n1. Account ID.\n2. Phone model used on the account.\n3. Phone number or email currently linked to the account.\n4. Account registration date on SUGO.\n5. Last time the account was opened.\n6. If you are a supporter: send the latest recharge invoice.\n7. If you are a host: send the target for the current month and the previous month.\n\nPlease make sure all answers are clear and complete so we can review your request.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "أسئلة إثبات ملكية الحساب", [{"label": "الاستخدام", "text": "يستخدم في حالات ربط الحساب أو استعادته أو مشاكل الرقم/الإيميل أو التحقق من الملكية."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nللتأكد من ملكية الحساب، يرجى الإجابة على أسئلة الأمان التالية في رسالة واحدة وبنفس الترتيب:\n\n1. الآي دي الخاص بالحساب.\n2. نوع الهاتف المستخدم على الحساب.\n3. الرقم أو البريد الإلكتروني المرتبط بالحساب حاليًا.\n4. تاريخ تسجيل الحساب على سوجو.\n5. آخر مرة تم فيها فتح الحساب.\n6. إذا كنت داعمًا: يرجى إرسال آخر فاتورة شحن.\n7. إذا كنت مضيفًا/مضيفة: يرجى إرسال تارجت الشهر الحالي والشهر الماضي.\n\nيرجى التأكد من أن جميع الإجابات واضحة وكاملة حتى نتمكن من مراجعة طلبك.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-unban-video", createSupportMacroContent("Unban Identity Video", [{"label": "Use Case", "text": "Use when identity verification is required for an unban request."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo review the unban request, please send a clear video showing your face. In the video, please state your full name and full SUGO ID, while holding your personal ID card next to your face.\n\nPlease send the video here in the conversation so the administration can verify your identity.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "فيديو التحقق لطلب فك الحظر", [{"label": "الاستخدام", "text": "يستخدم عندما تكون الإدارة بحاجة إلى التحقق من الهوية لمراجعة طلب فك الحظر."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nلمراجعة طلب فك الحظر، يرجى إرسال فيديو واضح يظهر فيه وجهك. خلال الفيديو، يرجى ذكر اسمك الكامل والآي دي الكامل في سوجو، مع حمل البطاقة الشخصية بجانب الوجه.\n\nيرجى إرسال الفيديو هنا داخل المحادثة حتى تتمكن الإدارة من التحقق من الهوية.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-verification-rejected", createSupportMacroContent("Verification Rejected", [{"label": "Use Case", "text": "Use when verification is rejected because the same verification was already used on another account."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nYour verification was rejected because the same verification information is already being used on another account.\n\nPlease make sure to use your own correct verification information.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "رفض التوثيق", [{"label": "الاستخدام", "text": "يستخدم عندما يتم رفض التوثيق لأن نفس بيانات التوثيق مستخدمة على حساب آخر."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nتم رفض توثيق حسابك لأن بيانات التوثيق نفسها مستخدمة بالفعل على حساب آخر.\n\nيرجى التأكد من استخدام بيانات التوثيق الصحيحة والخاصة بك.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-high-risk", createSupportMacroContent("High-Risk Restriction", [{"label": "Use Case", "text": "Use when the customer has a function restriction due to high-risk account status."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nWe apologize for the function restriction on your account.\n\nTo help resolve the issue, please complete one of the following options:\n\n1. Go to the Verification Center, complete gender verification, verify your profile photo, bind the account to a phone number, and recharge at least 50,000 coins.\n\nOr:\n\n2. Join an agency.\n\nAfter completing one of these requirements, the restriction should be reviewed by the system.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "تقييد الحساب عالي الخطورة", [{"label": "الاستخدام", "text": "يستخدم عندما يكون لدى العميل تقييد في الوظائف بسبب حالة خطورة الحساب."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nللمساعدة في حل المشكلة، يرجى تنفيذ أحد الخيارين التاليين:\n\n1. الدخول إلى مركز التحقق، ثم إتمام التحقق من الجنس، وتوثيق صورة البروفايل، وربط الحساب برقم الهاتف، ثم شحن 50,000 كوينز على الأقل.\n\nأو:\n\n2. الانضمام إلى وكالة.\n\nبعد تنفيذ أحد هذه الشروط، من المفترض أن تتم مراجعة التقييد من خلال النظام.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-report-abuse", createSupportMacroContent("Report Abuse Evidence", [{"label": "Use Case", "text": "Use when the customer wants to report abuse in a private chat or voice room."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo report abuse in a private chat or voice room, please send a clear screen recording that includes the following steps:\n\n1. Open the SUGO app.\n2. Open the full chat, or show the evidence of the abuse inside the voice room.\n3. Open the violator’s profile and show their account details, then show your own account details as well.\n4. Open any browser, type the current time, and show it in the video.\n\nAfter receiving the evidence, we will forward the report to the relevant team for review.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب دليل بلاغ إساءة", [{"label": "الاستخدام", "text": "يستخدم عندما يريد العميل الإبلاغ عن إساءة في محادثة خاصة أو غرفة صوتية."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nللإبلاغ عن إساءة في محادثة خاصة أو غرفة صوتية، يرجى إرسال فيديو تسجيل شاشة واضح يتضمن الخطوات التالية:\n\n1. فتح تطبيق سوجو.\n2. فتح المحادثة كاملة، أو عرض الدليل الخاص بالإساءة داخل الغرفة الصوتية.\n3. فتح حساب الشخص المسيء وعرض بياناته، ثم عرض حسابك أنت أيضًا.\n4. فتح أي متصفح، وكتابة الوقت الحالي وإظهاره في الفيديو.\n\nبعد استلام الدليل، سيتم تحويل البلاغ إلى القسم المختص للمراجعة.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-ban-reason", createSupportMacroContent("Ban / Restriction Reason", [{"label": "Use Case", "text": "Use when informing the customer that the ban or restriction reason should be provided by the agent according to the reviewed case."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nAfter review, the reason for the ban/restriction is: [write the confirmed reason here].\n\nIf you believe this decision needs to be reviewed again, please send the required evidence or verification details in this conversation.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "سبب الحظر أو التقييد", [{"label": "الاستخدام", "text": "يستخدم عندما يحتاج الموظف إلى كتابة سبب الحظر أو التقييد حسب الحالة بعد المراجعة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nبعد المراجعة، سبب الحظر/التقييد هو: [اكتب السبب المؤكد هنا].\n\nإذا كنت ترى أن القرار يحتاج إلى مراجعة مرة أخرى، يرجى إرسال الدليل المطلوب أو بيانات التحقق داخل هذه المحادثة.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-moments-watermark", createSupportMacroContent("Moments / Watermark Removal", [{"label": "Use Case", "text": "Use when a moment or album is rejected due to ads, external products, or watermarks."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nPlease remove any advertisements, external product images, or watermarks from your Moments or Albums before publishing again.\n\nAfter removing them, you may try posting again.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "إزالة الإعلانات أو العلامات المائية", [{"label": "الاستخدام", "text": "يستخدم عندما يتم رفض اللحظات أو الألبومات بسبب وجود إعلانات أو منتجات خارجية أو علامات مائية."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nيرجى إزالة أي إعلانات أو صور منتجات خارجية أو علامات مائية من اللحظات أو الألبومات قبل النشر مرة أخرى.\n\nبعد الإزالة، يمكنك محاولة النشر مجددًا.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-recharge-methods", createSupportMacroContent("Recharge Methods", [{"label": "Use Case", "text": "Use when the customer asks how to recharge or needs the available recharge methods."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nTo continue chatting, send unlimited messages, send gifts, write comments, create voice rooms, post moments, and enjoy games, you may need to recharge more coins.\n\nYou can check recharge methods and prices through your profile:\n\n1. Go to your profile page.\n2. Open Recharge.\n3. Choose the coin package you want.\n4. Select the suitable payment method.\n\nAvailable methods may include Google, iTunes, Visa, and STC Pay in Saudi Arabia. You can also use the official recharge link:\nhttps://web-app.voicemaker.media/web/pay.html\n\nPlease note: if this is your first recharge, Visa may be required. Other methods may become available after reaching VIP level 4, depending on your region and account status.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طرق وخطوات الشحن", [{"label": "الاستخدام", "text": "يستخدم عندما يسأل العميل عن طريقة الشحن أو طرق الدفع المتاحة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nحتى تتمكن من متابعة المحادثة، وإرسال رسائل بلا حدود، وإرسال الهدايا، وكتابة التعليقات، وإنشاء غرف صوتية، ونشر اللحظات، والاستمتاع بالألعاب، قد تحتاج إلى شحن المزيد من الكوينز.\n\nيمكنك معرفة طرق الشحن والأسعار من خلال صفحتك الشخصية:\n\n1. الدخول إلى الصفحة الشخصية.\n2. فتح خانة إعادة الشحن.\n3. اختيار باقة الكوينز المطلوبة.\n4. اختيار طريقة الدفع المناسبة.\n\nقد تكون طرق الشحن المتاحة مثل Google و iTunes و Visa و STC Pay داخل السعودية. ويمكنك أيضًا استخدام رابط الشحن الرسمي:\nhttps://web-app.voicemaker.media/web/pay.html\n\nيرجى العلم: إذا كانت هذه أول عملية شحن، فقد يلزم استخدام بطاقة Visa. وقد تظهر طرق أخرى بعد الوصول إلى مستوى VIP 4 حسب الدولة وحالة الحساب.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-invoice", createSupportMacroContent("Request Recharge Invoice", [{"label": "Use Case", "text": "Use when a recharge issue requires proof of payment."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nPlease clarify when the recharge was made and send the recharge invoice showing the date, time, and transaction number.\n\nIf payment was made through a bank, please send the bank invoice. If it was made through a wallet, please send the invoice from the wallet app.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب فاتورة الشحن", [{"label": "الاستخدام", "text": "يستخدم عندما تحتاج مشكلة الشحن إلى إثبات دفع."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nيرجى توضيح وقت إتمام عملية الشحن، مع إرسال فاتورة الشحن التي تحتوي على التاريخ والوقت ورقم العملية.\n\nإذا كان الدفع من خلال البنك، يرجى إرسال الفاتورة البنكية. وإذا كان الدفع من خلال محفظة، يرجى إرسال الفاتورة من تطبيق المحفظة.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-recharge-failed", createSupportMacroContent("Recharge Failed / Alternatives", [{"label": "Use Case", "text": "Use when the customer cannot complete recharge and needs alternative official methods."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nYou can try recharging through the official SUGO link:\nhttps://web-app.voicemaker.media/web/pay.html\n\nYou can also recharge through verified recharge agents inside the app.\n\nTo contact a verified agent:\n1. Open Messages.\n2. Tap the search icon.\n3. Enter the suitable agent ID and search.\n4. Open the agent profile and send a message. Messaging verified recharge agents inside the app is free.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "فشل الشحن وطرق بديلة", [{"label": "الاستخدام", "text": "يستخدم عندما لا يتمكن العميل من إتمام الشحن ويحتاج إلى طرق رسمية بديلة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nيمكنك تجربة الشحن من خلال الرابط الرسمي الخاص بسوجو:\nhttps://web-app.voicemaker.media/web/pay.html\n\nيمكنك أيضًا الشحن من خلال وكلاء الشحن الموثقين داخل التطبيق.\n\nللتواصل مع وكيل موثق:\n1. الدخول إلى الرسائل.\n2. الضغط على علامة البحث.\n3. إدخال الآي دي المناسب والبحث عنه.\n4. فتح صفحة الوكيل وإرسال رسالة له. التواصل مع وكلاء الشحن الموثقين داخل التطبيق مجاني.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-insufficient-coins", createSupportMacroContent("Insufficient Coins for Messages", [{"label": "Use Case", "text": "Use when the customer cannot send messages because the account has insufficient coins."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nThe reason you cannot send messages is that your account does not currently have enough coins. Messages require coins, so you need to recharge before sending more messages.\n\nYou can recharge from your profile through the Recharge section, or use the official link:\nhttps://web-app.voicemaker.media/web/pay.html\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "عدم كفاية العملات للرسائل", [{"label": "الاستخدام", "text": "يستخدم عندما لا يستطيع العميل إرسال الرسائل بسبب عدم وجود كوينز كافية."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nسبب عدم قدرتك على إرسال الرسائل هو أن حسابك لا يحتوي حاليًا على كوينز كافية، حيث إن إرسال الرسائل يحتاج إلى كوينز. لذلك يجب الشحن قبل متابعة إرسال الرسائل.\n\nيمكنك الشحن من خلال خانة إعادة الشحن داخل صفحتك الشخصية، أو عبر الرابط الرسمي:\nhttps://web-app.voicemaker.media/web/pay.html\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-elite-club", createSupportMacroContent("Elite Club Conditions", [{"label": "Use Case", "text": "Use when the customer asks about joining the Elite Club."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo join the Elite Club, you need to recharge 1,500 USD.\n\nAfter completing the recharge, you may be added to the Elite Club in the following month through the VIP Customer Service team.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "شروط نادي النخبة", [{"label": "الاستخدام", "text": "يستخدم عندما يسأل العميل عن الانضمام إلى نادي النخبة."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nللانضمام إلى نادي النخبة، يجب الشحن بقيمة 1,500 دولار أمريكي.\n\nبعد إتمام الشحن، يمكن إضافتك إلى نادي النخبة في الشهر التالي من خلال خدمة عملاء كبار الداعمين.\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-apply-agency", createSupportMacroContent("Apply to Open Host Agency", [{"label": "Use Case", "text": "Use when the customer asks how to open a host agency."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nTo open a host agency in the app, the minimum requirement is 5 new hosts with new accounts and new devices.\n\nIf the conditions are available, please send the following information so the request can be submitted to the administration:\n\n1. ID:\n2. Name:\n3. WhatsApp number with international code:\n4. Country:\n5. Do you currently have an agency on another app?\n\nThe administration may contact you within 24 to 48 hours via WhatsApp to explain the full details.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب فتح وكالة مضيفات", [{"label": "الاستخدام", "text": "يستخدم عندما يسأل العميل عن طريقة فتح وكالة مضيفات."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nلفتح وكالة مضيفات داخل التطبيق، يجب توفر 5 مضيفات جدد كحد أدنى، بحسابات جديدة وأجهزة جديدة.\n\nإذا كانت الشروط متوفرة، يرجى إرسال البيانات التالية حتى يتم تقديم الطلب للإدارة:\n\n1. الآي دي:\n2. الاسم:\n3. رقم واتساب بالكود الدولي:\n4. الدولة:\n5. هل لديك وكالة في تطبيق آخر؟\n\nقد يتم التواصل معك من خلال الإدارة خلال 24 إلى 48 ساعة عبر واتساب لشرح التفاصيل كاملة.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-change-agency", createSupportMacroContent("Agency Transfer Request", [{"label": "Use Case", "text": "Use when a host asks to transfer from one agency to another."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nIf you want to transfer from your current agency, there are two possible ways:\n\n1. The current agent agrees and submits the transfer request to the administration.\n\nOr:\n\n2. If you have been inactive for two months, you may send a transfer request to the new agent.\n\nPlease provide the following information:\n\n1. ID:\n2. Phone number linked to the account:\n3. Name and ID of the current agency:\n4. Name and ID of the agency you want to transfer to:\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "طلب نقل الوكالة", [{"label": "الاستخدام", "text": "يستخدم عندما ترغب المضيفة/المضيف بالانتقال من وكالة إلى أخرى."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nإذا كنت ترغب في النقل من الوكالة المسجل بها حاليًا، فهناك طريقتان للنقل:\n\n1. موافقة الوكيل الحالي، ثم يقوم هو بتقديم طلب النقل إلى الإدارة.\n\nأو:\n\n2. في حال التوقف لمدة شهرين، يمكنك إرسال طلب نقل إلى الوكيل الجديد.\n\nيرجى إرسال البيانات التالية:\n\n1. الآي دي:\n2. رقم الهاتف المرتبط بالحساب:\n3. اسم وآي دي الوكالة المسجل بها حاليًا:\n4. اسم وآي دي الوكالة المراد النقل إليها:\n\nنكرر اعتذارنا الخالص عن الإزعاج الذي تسببنا به، ونشكركم جزيل الشكر على صبركم وسعة صدركم. نتمنى لكم يوماً سعيداً وموفقاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-games-conditions", createSupportMacroContent("Games Access Conditions", [{"label": "Use Case", "text": "Use when the customer asks why games are not available or what the access requirements are."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nGames are available only when the account meets the required conditions.\n\nFor Android users:\n• Host: charm level 3 is required.\n• Supporter: VIP4 is required.\n\nFor iPhone users:\n• Host: charm level 2 is required.\n• Supporter: VIP3 is required.\n\nAdditional access may also depend on coin spending outside games during the current or previous week.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "شروط ظهور الألعاب", [{"label": "الاستخدام", "text": "يستخدم عندما يسأل العميل عن سبب عدم ظهور الألعاب أو شروط الوصول إليها."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nالألعاب تكون متاحة فقط عند استيفاء الحساب للشروط المطلوبة.\n\nلمستخدمي أندرويد:\n• إذا كنت مضيفًا/مضيفة: يجب أن يكون مستوى الجاذبية 3.\n• إذا كنت داعمًا: يجب أن يكون الحساب VIP4.\n\nلمستخدمي آيفون:\n• إذا كنت مضيفًا/مضيفة: يجب أن يكون مستوى الجاذبية 2.\n• إذا كنت داعمًا: يجب أن يكون الحساب VIP3.\n\nقد يعتمد الوصول أيضًا على استهلاك الكوينز خارج الألعاب خلال الأسبوع الحالي أو السابق.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-games-add-remove", createSupportMacroContent("Add / Remove Games Request", [{"label": "Use Case", "text": "Use when the customer asks to add or remove games from the account."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe are very happy and honored to have you with us.\nHow can we assist you today?\n\nYour request to [add/remove] games has been submitted.\n\nThe request will be reviewed and processed as soon as possible.\n\nThank you for contacting SUGO. We are always happy to serve you. We wish you a wonderful day!\n\nSUGO Customer Service Team"}], "طلب إضافة أو إزالة الألعاب", [{"label": "الاستخدام", "text": "يستخدم عندما يطلب العميل إضافة أو إزالة الألعاب من الحساب."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nيسعدنا ويشرفنا جداً تواجدك معنا.\nكيف يمكننا مساعدتك اليوم؟\n\nتم تقديم طلب [إضافة/إزالة] الألعاب.\n\nسيتم مراجعة الطلب والعمل عليه في أقرب وقت ممكن.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
setPane("sv-clean-daily-family-tasks", createSupportMacroContent("Daily and Family Tasks", [{"label": "Use Case", "text": "Use when the customer asks about daily or family task requirements."}, {"label": "Ticket", "text": "Welcome to the SUGO family!\nWe sincerely apologize for the issue you are experiencing.\n\nDaily and family tasks have specific requirements:\n\n1. Complete frame verification and gender verification.\n2. Have a recharge record within the last 30 days.\n3. Account level must be 4 or higher.\n4. Charm level must be 5 or higher.\n\nIf the account meets the recharge requirement, the feature may become active. If all requirements are met, the feature may become active the next day.\n\nWe once again sincerely apologize for the inconvenience we have caused, and we truly thank you for your patience and understanding. We wish you a happy and successful day!\n\nSUGO Customer Service Team"}], "شروط المهام اليومية والعائلية", [{"label": "الاستخدام", "text": "يستخدم عندما يسأل العميل عن شروط المهام اليومية أو العائلية."}, {"label": "التذكرة", "text": "مرحباً بك في عائلة سوجو!\nنعتذر جداً على المشكلة التي تواجهك\n\nللمهام اليومية والعائلية شروط محددة:\n\n1. اجتياز التحقق من الإطار والتحقق من الجنس.\n2. وجود سجل شحن خلال آخر 30 يومًا.\n3. يجب أن يكون مستوى الحساب 4 أو أكثر.\n4. يجب أن يكون مستوى الجاذبية 5 أو أكثر.\n\nإذا استوفى الحساب شرط الشحن، قد يتم تفعيل الخاصية. وإذا تم استيفاء جميع الشروط، قد يتم تفعيل الخاصية في اليوم التالي.\n\nشكراً لتواصلك مع سوجو، يسعدنا دائماً خدمتك. نتمنى لك يوماً رائعاً!\n\nفريق خدمة عملاء سوجو"}]));
